@Test
public void testAddNaNLeft() {
    Complex x = Complex.NaN;
    Complex y = new Complex(3.0, 4.0);
    Complex z = x.add(y);
    Assert.assertTrue(z.isNaN());
}

@Test
public void testAddBothNaN() {
    Complex x = Complex.NaN;
    Complex y = Complex.NaN;
    Complex z = x.add(y);
    Assert.assertTrue(z.isNaN());
}

@Test
public void testAddNaNRealPart() {
    Complex x = new Complex(2.0, 3.0);
    Complex y = new Complex(Double.NaN, 5.0);
    Complex z = x.add(y);
    Assert.assertTrue(Double.isNaN(z.getReal()));
    Assert.assertTrue(Double.isNaN(z.getImaginary()));
}

@Test
public void testAddNaNImaginaryPart() {
    Complex x = new Complex(2.0, 3.0);
    Complex y = new Complex(5.0, Double.NaN);
    Complex z = x.add(y);
    Assert.assertTrue(Double.isNaN(z.getReal()));
    Assert.assertTrue(Double.isNaN(z.getImaginary()));
}
